import{_ as a,o as t,c as o,ao as i}from"./chunks/framework.BwTKejc4.js";const p=JSON.parse('{"title":"R ↔ Julia bridge","description":"","frontmatter":{},"headers":[],"relativePath":"r-julia-bridge.md","filePath":"r-julia-bridge.md","lastUpdated":null}'),r={name:"r-julia-bridge.md"};function s(d,e,l,n,c,h){return t(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="R-Julia-bridge" tabindex="-1">R ↔ Julia bridge <a class="header-anchor" href="#R-Julia-bridge" aria-label="Permalink to &quot;R ↔ Julia bridge {#R-Julia-bridge}&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">Status — Planned (Phase 1.5)</p><p>This page describes the <strong>intended</strong> bridge that lets an R user run drmTMB&#39;s front end on the DRM.jl engine: <code>drmTMB(formula, …, engine = &quot;julia&quot;)</code>. The R-side glue lives in the <strong>drmTMB R repository</strong> (via <a href="https://github.com/JuliaInterop/JuliaCall" target="_blank" rel="noreferrer">JuliaCall</a>), not in this package, so the steps below are the design + the DRM.jl-side contract, not a shipped feature. For translating R syntax to Julia by hand today, see the <a href="./rosetta">Rosetta page</a>.</p></div><h2 id="The-idea" tabindex="-1">The idea <a class="header-anchor" href="#The-idea" aria-label="Permalink to &quot;The idea {#The-idea}&quot;">​</a></h2><p>Two ways to use DRM.jl from R, in increasing integration:</p><ol><li><p><strong>Translate by hand</strong> — rewrite the model in Julia using <code>drm</code> / <code>bf</code>. The <a href="./rosetta">Rosetta</a> phrasebook is the lookup table. Available today.</p></li><li><p><strong><code>engine = &quot;julia&quot;</code></strong> — keep writing ordinary <code>drmTMB(...)</code> R code; drmTMB marshals the formula and data across JuliaCall, calls DRM.jl to fit, and returns a result object shaped like a native drmTMB fit. Planned (Phase 1.5).</p></li></ol><h2 id="The-DRM.jl-side-contract" tabindex="-1">The DRM.jl-side contract <a class="header-anchor" href="#The-DRM.jl-side-contract" aria-label="Permalink to &quot;The DRM.jl-side contract {#The-DRM.jl-side-contract}&quot;">​</a></h2><p>For the bridge to work, DRM.jl exposes a stable, marshalling-friendly surface:</p><ul><li><p><strong>Formula</strong> — the R <code>bf(mu = y ~ x, sigma = ~ x, …)</code> is mapped to DRM.jl&#39;s <code>bf(...)</code> (see the <a href="./developer-notes/formula-grammar">Formula grammar</a> and Rosetta pages for the exact spelling map);</p></li><li><p><strong>Data</strong> — an R <code>data.frame</code> crosses as a column table (<code>NamedTuple</code> / <code>DataFrame</code>) keyed by the same column names;</p></li><li><p><strong>Result</strong> — the fitted <code>DrmFit</code> exposes the accessors R expects (<code>coef</code>, <code>vcov</code>, <code>loglik</code>, <code>aic</code>/<code>bic</code>, <code>confint</code>, <code>fitted</code>, <code>residuals</code>, <code>predict</code>, <code>simulate</code>, <code>ranef</code>/<code>vc</code>), so the R wrapper can reconstruct a drmTMB-shaped object.</p></li></ul><h2 id="Open-design-questions" tabindex="-1">Open design questions <a class="header-anchor" href="#Open-design-questions" aria-label="Permalink to &quot;Open design questions {#Open-design-questions}&quot;">​</a></h2><p>Tracked in the issue ledger:</p><ul><li><p><strong>Phylo / pedigree / relatedness marshalling</strong> — how a Newick tree, an <code>Ainv</code>, or a <code>K</code> matrix crosses the R ↔ Julia boundary (issue #19).</p></li><li><p><strong>Result-shape parity</strong> — exact field-by-field equivalence between a native drmTMB fit and the Julia-engine fit (issue #5), guarded by the R-parity suite (Workflow G, issue #17).</p></li><li><p><strong>Round-trip <code>bf()</code> formulas</strong> — an R formula and its Julia translation must describe the same model; the parity tests enforce this once R is available in CI.</p></li></ul><p>Until the bridge ships, the supported path is hand-translation via the Rosetta phrasebook.</p>',12)])])}const g=a(r,[["render",s]]);export{p as __pageData,g as default};
